function _reverse(uint256 input) private pure returns (uint256) {
    uint256 res = 0;
    uint256 shifted = input;
    uint256 mask = 0xff;

    for (uint i = 0; i < 32; ++i) {
      uint256 oneByte = (shifted & mask) << ((32 - i - 1) * 8);
      shifted = shifted >> 8;
      res = res + oneByte;
    }

    return res;
  }

